'use strict';
const fs = require('fs');
const path = require('path');
const { allProducts } = require('../core/products');
const { AppError } = require('../lib/errors');
const config = require('../config');

function parseFormat(args) {
  const idx = args.indexOf('--format');
  if (idx !== -1 && args[idx + 1]) {
    return args[idx + 1];
  }
  return 'json';
}

function exportProducts(args) {
  const fmt = parseFormat(args);
  if (fmt !== 'json' && fmt !== 'csv') {
    throw new AppError('unsupported format: ' + fmt, 2);
  }

  const products = allProducts();
  const ext = fmt;
  const filepath = path.join(config.outputDir, 'products.' + ext);

  let content;
  if (fmt === 'csv') {
    const header = 'id,name,price';
    const rows = products.map(p => {
      const name = String(p.name).includes(',') ? p.name : p.name;
      return [p.id, name, p.price.toFixed(2)].join(',');
    });
    content = [header, ...rows].join('\n');
  } else {
    content = JSON.stringify(products, null, 2);
  }

  fs.mkdirSync(config.outputDir, { recursive: true });
  fs.writeFileSync(filepath, content);

  return ['Exported ' + products.length + ' products to ' + filepath];
}

module.exports = { exportProducts };

'use strict';
const fs = require('fs');
const path = require('path');
const { allOrders, orderTotal } = require('../core/orders');
const { AppError } = require('../lib/errors');
const config = require('../config');

function parseFormat(args) {
  const idx = args.indexOf('--format');
  if (idx !== -1 && args[idx + 1]) {
    return args[idx + 1];
  }
  return 'json';
}

function exportOrders(args) {
  const fmt = parseFormat(args);
  if (fmt !== 'json' && fmt !== 'csv') {
    throw new AppError('unsupported format: ' + fmt, 2);
  }

  const orders = allOrders();
  const ext = fmt;
  const filepath = path.join(config.outputDir, 'orders.' + ext);

  let content;
  if (fmt === 'csv') {
    const header = 'id,customerId,total';
    const rows = orders.map(o => {
      const total = orderTotal(o).toFixed(2);
      return [o.id, o.customerId, total].join(',');
    });
    content = [header, ...rows].join('\n');
  } else {
    const records = orders.map(o => ({
      id: o.id,
      customerId: o.customerId,
      total: parseFloat(orderTotal(o).toFixed(2)),
    }));
    content = JSON.stringify(records, null, 2);
  }

  fs.mkdirSync(config.outputDir, { recursive: true });
  fs.writeFileSync(filepath, content);

  return ['Exported ' + orders.length + ' orders to ' + filepath];
}

module.exports = { exportOrders };

